{!REQUIRESCRIPT("/soap/ajax/14.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/14.0/apex.js")} 

var message = "Certifying the income for Service File will copy information into certified fields in this file, and will overwrite any previously certified values.\n\n- Income Certification Date is set to the current date\n- Certified AMI for Household Size is copied from AMI for Household Size\n- Certified Annual Income (Gross) is copied from Annual Income (Gross)\n- Certified Annual Income (Eligibility) is copied from Annual Income (Eligibility)\n- Certified Eligibility Income Calculation is copied from Eligibility Income Calculation\n- Certified Household Size is copied from Household Size\n- Certified 4-Person AMI is calculated\n\nYou cannot un-certify the income, but if you need to make a correction, you can recertify. The uncertified fields will always copy over the certified fields.\n\nAre you ready to continue?"

confirmed = window.confirm(message); 

if (confirmed) 
{ 
// run the webservice 
var serviceFileID = sforce.apex.execute("HOMEtracker.ServiceFileWebServices","certifyIncome", {serviceFileID: "{!CASESAFEID(HOMEtracker__Service_File__c.Id)}"}); 

// redirect to the new task 
top.location.replace("/" + serviceFileID); 
}
